                                                .scaledToFit()
                                                .onTapGesture {
                                                    addSticker(UIImage(named: stickerNames[idx]), at: addPoint)
                                                    store.send(.setBottomSheetCollapsed(true))
                                                }
                                        }
                                    }
                                }
                            }
                        }
                    }
                    .padding(.horizontal, 16)
                }
            }
        }
    }

    func titleView() -> some View {
        WithPerceptionTracking {
            let baseImage = store.baseImage
            let stickers  = store.stickers

            HStack(spacing: 0) {
                BackButton()
                    .onTapGesture {
                        store.send(.onBackButtonTapped)
                    }

                Spacer()

                CTAButton(text: "완성", type: .orange, size: .compact, maxWidth: 65) {
                    deselectAll()

                    // 이미지 렌더링을 위한 데이터 같이 전달
                    store.send(.onCompleteButtonTapped(baseImage, stickers, {
                        AnyView(ZStack {
                            WithPerceptionTracking {
                                ForEach(stickers) { sticker in
                                    stickerView(with: sticker.id, onSelect: {}, onDelete: {})
                                        .zIndex(Double((stickers.index(id: sticker.id) ?? 0) + 1))
                                }
                            }
                        })
                    }))
                }
                .frame(width: 65)
            }
            .frame(height: 64, alignment: .center)
            .padding(.horizontal, 20)
        }
    }

    func canvasView() -> some View {
        GeometryReader { geo in
            WithPerceptionTracking {
                let baseImage = store.baseImage
                let stickers  = store.stickers
                let imageSize = store.imageSize

                ComposedCanvasView(baseImage: baseImage, size: imageSize, stickers: stickers, stickerView: {
                    ZStack {
                        WithPerceptionTracking {
                            ForEach(stickers) { sticker in
                                stickerView(with: sticker.id, onSelect: {
                                    bringToFront(sticker.id)
                                    select(sticker.id)
                                }, onDelete: {
                                    removeSticker(sticker.id)
                                })
                                .zIndex(Double((stickers.index(id: sticker.id) ?? 0) + 1))
                            }
                        }
                    }
                })
                .onTapGesture { // 빈 공간 탭 → 선택 해제
                    deselectAll()
                }
                .onAppear {
                    store.send(.updateImageSize(.init(width: geo.size.width, height: geo.size.width * (baseImage.size.height / baseImage.size.width))))
                }
            }
        }
    }

    func addSticker(_ uiImage: UIImage?, at point: CGPoint) {
        guard let uiImage else { return }
        let newSticker = Sticker(uiImage: uiImage, position: point)
        store.send(.addSticker(newSticker))
        deselectAll()
        bringToFront(newSticker.id)
        select(newSticker.id)
    }

    func removeSticker(_ id: UUID) {
        store.send(.removeSticker(id))
    }

    func select(_ id: UUID?) {
        deselectAll()
        store.send(.updateSelectedSticker(id))
    }

    func deselectAll() {
        store.send(.updateSelectedSticker(nil))
    }

    func bringToFront(_ id: UUID) {
        store.send(.bringToFront(id))
    }

    func stickerView(with stickerID: UUID, onSelect: @escaping () -> Void, onDelete: @escaping () -> Void) -> some View {
        WithPerceptionTracking {
            let sticker = store.stickers.element(id: stickerID) ?? Sticker(uiImage: UIImage(), position: .zero)

            let minScale: CGFloat = 0.5 // 최소 배율
            let maxScale: CGFloat = 5.0 // 최대 배율

            let currentScale = store.currentScale[sticker.id] ?? 1
            let currentRotation = store.currentRotation[sticker.id] ?? .degrees(0)
            let dragOffset = store.dragOffset[sticker.id] ?? .zero

            let drag = DragGesture()
                .onChanged { value in
                    store.send(.onDragOffsetChanged(sticker.id, value.translation))
                }
                .onEnded { value in
                    var newSticker = sticker
                    newSticker.position.x += value.translation.width
                    newSticker.position.y += value.translation.height

                    store.send(.onDragOffsetChanged(newSticker.id, .zero))
                    store.send(.onFinalDragOffsetChanged(newSticker.id, newSticker.position))
                }

            let pinch = MagnificationGesture()
                .onChanged { value in
                    store.send(.onScaleChanged(sticker.id, value))
                }
                .onEnded { value in
                    var newSticker = sticker
                    newSticker.scale *= value
                    store.send(.onFinalScaleChanged(sticker.id, newSticker.scale))
                    store.send(.onScaleChanged(newSticker.id, 1))
                }

            let rotate = RotationGesture()
                .onChanged { value in
                    store.send(.onRotationChanged(sticker.id, value))
                }
                .onEnded { value in
                    var newSticker = sticker
                    newSticker.rotation += value
                    store.send(.onFinalRotationChanged(sticker.id, newSticker.rotation))
                    store.send(.onRotationChanged(newSticker.id, .degrees(0)))
                }

            let combined = drag.simultaneously(with: pinch).simultaneously(with: rotate)

            return ZStack(alignment: .topLeading) {
                Image(uiImage: sticker.uiImage)
                    .resizable()
                    .scaledToFit()
                    .frame(width: 80)
                    .overlay {
                        WithPerceptionTracking {
                            if sticker.isSelected {
                                Rectangle()
                                    .stroke(style: StrokeStyle(lineWidth: 1 / max(sticker.scale * currentScale, minScale)))
                                    .foregroundStyle(.white)
                            }
                        }
                    }
                    .overlay(alignment: .topLeading) { // 닫기 버튼
                        WithPerceptionTracking {
                            if sticker.isSelected {
                                Button {
                                    onDelete()
                                } label: {
                                    Image(.imageClose)
                                        .resizable()
                                        .frame(width: 20, height: 20)
                                }
                                .scaleEffect(1 / max(sticker.scale * currentScale, minScale))
                                .rotationEffect(-(sticker.rotation + currentRotation))
                                .offset(x: -10, y: -10)
                            }
                        }
                    }
                    .overlay(alignment: .bottomTrailing) { // 핀치 버튼
                        GeometryReader { proxy in
                            if sticker.isSelected {
                                WithPerceptionTracking {
                                    // 현재(진행 중 포함) 회전
                                    let theta = (sticker.rotation + currentRotation).radians
                                    let cosT = cos(theta), sinT = sin(theta)

                                    let baseW: CGFloat = proxy.size.width
                                    let baseH: CGFloat = proxy.size.height

                                    // 로컬 우하단 코너 벡터 v
                                    let vx = baseW / 2, vy = baseH / 2
                                    let vDotv = vx*vx + vy*vy

                                    let pinchHandle = Image(.imagePinch)
                                        .resizable()
                                        .frame(width: 20, height: 20)
                                        .scaleEffect(1 / max(sticker.scale * currentScale, minScale))
                                        .rotationEffect(-(sticker.rotation + currentRotation))
                                        .offset(x: 10, y: 10)
                                        .gesture(
                                            DragGesture(coordinateSpace: .global)
                                                .onChanged { value in
                                                    // 중심 (현재 레이아웃의 글로벌 센터)
                                                    let center = proxy.frame(in: .global).center

                                                    // 손가락 글로벌 → 로컬로 역회전
                                                    let dx = value.location.x - center.x
                                                    let dy = value.location.y - center.y
                                                    let lx =  cosT * dx + sinT * dy      // R(-θ) * (F - center)
                                                    let ly = -sinT * dx + cosT * dy

                                                    // v 방향으로의 스케일 s
                                                    var s = (lx*vx + ly*vy) / max(vDotv, 0.001)

                                                    // 최소 배율 지정
                                                    s = max(s, 0.5)

                                                    var next = sticker
                                                    next.scale = s
                                                    store.send(.onStickerStateChanged(next))
                                                }
                                        )

                                    ZStack(alignment: .bottomTrailing) {
                                        pinchHandle
                                    }
                                    .frame(maxWidth: .infinity, maxHeight: .infinity, alignment: .bottomTrailing)
                                }
                            }
                        }
                    }
                    .onTapGesture {
                        onSelect()
                    }
            }
            .scaleEffect(max(sticker.scale * currentScale, minScale))
            .rotationEffect(sticker.rotation + currentRotation)
            .position(x: sticker.position.x + dragOffset.width, y: sticker.position.y + dragOffset.height)
            .if(sticker.isSelected) { view in
                view.gesture(combined)
            }
        }
    }
}

private extension CGRect {
    var center: CGPoint { .init(x: midX, y: midY) }
}

extension View {
    @ViewBuilder
    func `if`<Content: View>(_ condition: Bool, transform: (Self) -> Content) -> some View {
        if condition {
            transform(self)
        } else {
            self
        }
    }
}

