import SwiftUI
import ComposableArchitecture

struct StatisticsView: View {
    @Perception.Bindable private var store: StoreOf<StatisticsFeature>

    init(store: StoreOf<StatisticsFeature>) {
        self.store = store
    }

    var body: some View {
        WithPerceptionTracking {
            VStack(spacing: 0) {
                NavigationTitleView(title: "통계") {
                    store.send(.backButtonTapped)
                }

                ScrollView {
                    VStack(spacing: 40) {
                        statisticsSectionView(title: "집중 시간") {
                            EmptyView()
                        }

                        statisticsSectionView(title: "휴식 시간") {
                            EmptyView()
                        }

                        statisticsSectionView(title: "집중 캘린더") {
                            calendarView
                        }

                        statisticsSectionView(title: "캐릭터 사용 빈도") {
                            EmptyView()
                        }
                    }
                    .padding(.horizontal, 20)
                    .padding(.vertical, 20)
                }
            }
            .navigationBarBackButtonHidden(true)
            .background(.coolGray25)
            .onLoad {
                store.send(.onLoaded)
            }
        }
    }
}

// MARK: - Section

private extension StatisticsView {
    func statisticsSectionView(title: String, @ViewBuilder content: () -> some View) -> some View {
        VStack(alignment: .leading, spacing: 0) {
            Text(title)
                .pretendardFont(weight: .semiBold600, size: 20)
                .kerning(0.5)
                .foregroundStyle(.coolGray900)
            content()
        }
        .padding(.vertical, 24)
        .padding(.horizontal, 16)
        .frame(maxWidth: .infinity, alignment: .leading)
        .background(.white)
        .cornerRadius(24)
    }
}

// MARK: - Calendar

private extension StatisticsView {
    var calendarView: some View {
        let columns = Array(repeating: GridItem(.flexible()), count: 7)
        let days = calendarDays(for: store.displayedMonth)
        let today = Calendar.current.dateComponents([.year, .month, .day], from: Date())

        return VStack(spacing: 16) {
            // 월 헤더
            HStack {
                Button {
                    store.send(.prevMonthTapped)
                } label: {
                    Image(systemName: "chevron.left")
                        .foregroundStyle(.coolGray400)
                }

                Spacer()

                Text(monthTitle(for: store.displayedMonth))
                    .pretendardFont(weight: .semiBold600, size: 16)
                    .foregroundStyle(.coolGray900)

                Spacer()

                Button {
                    store.send(.nextMonthTapped)
                } label: {
                    Image(systemName: "chevron.right")
                        .foregroundStyle(.coolGray400)
                }
            }
            .padding(.top, 8)

            // 요일 헤더
            LazyVGrid(columns: columns, spacing: 8) {
                ForEach(["일", "월", "화", "수", "목", "금", "토"], id: \.self) { weekday in
                    Text(weekday)
                        .pretendardFont(weight: .medium500, size: 12)
                        .foregroundStyle(.coolGray400)
                        .frame(maxWidth: .infinity)
                }
            }

            // 날짜 그리드
            LazyVGrid(columns: columns, spacing: 8) {
                ForEach(0..<days.count, id: \.self) { index in
                    if let day = days[index] {
                        let components = dayComponents(day: day, month: store.displayedMonth)
                        let isFocused = store.focusedDates.contains(components)
                        let isToday = components == today

                        ZStack {
                            if isFocused {
                                Circle().fill(Color.orange500)
                            } else if isToday {
                                Circle().fill(Color.coolGray900)
                            }

                            Text("\(day)")
                                .pretendardFont(weight: .medium500, size: 14)
                                .foregroundStyle(isFocused || isToday ? .white : .coolGray800)
                        }
                        .frame(maxWidth: .infinity)
                        .aspectRatio(1, contentMode: .fit)
                    } else {
                        Color.clear
                            .frame(maxWidth: .infinity)
                            .aspectRatio(1, contentMode: .fit)
                    }
                }
            }
        }
    }

    func monthTitle(for date: Date) -> String {
        let formatter = DateFormatter()
        formatter.locale = Locale(identifier: "ko_KR")
        formatter.dateFormat = "yyyy년 M월"
        return formatter.string(from: date)
    }

    func calendarDays(for month: Date) -> [Int?] {
        let calendar = Calendar.current
        guard
            let range = calendar.range(of: .day, in: .month, for: month),
            let firstDay = calendar.date(from: calendar.dateComponents([.year, .month], from: month))
        else { return [] }

        // 일요일 기준 첫 날의 요일 오프셋 (0=일, 1=월, ..., 6=토)
        let weekday = calendar.component(.weekday, from: firstDay) - 1

        var days: [Int?] = Array(repeating: nil, count: weekday)
        days += range.map { Optional($0) }
        return days
    }

    func dayComponents(day: Int, month: Date) -> DateComponents {
        let calendar = Calendar.current
        var components = calendar.dateComponents([.year, .month], from: month)
        components.day = day
        return components
    }
}

