import ComposableArchitecture
import Foundation

@Reducer
struct StatisticsFeature {
    @ObservableState
    struct State: Equatable {
        var displayedMonth: Date = Date()
        var focusedDates: Set<DateComponents> = []
    }

    enum Action {
        case onLoaded
        case backButtonTapped
        case prevMonthTapped
        case nextMonthTapped
    }

    @Dependency(\.dismiss) var dismiss

    var body: some ReducerOf<Self> {
        Reduce<State, Action> { state, action in
            switch action {
            case .onLoaded:
                return .none

            case .backButtonTapped:
                return .run { _ in
                    await self.dismiss()
                }

            case .prevMonthTapped:
                if let prev = Calendar.current.date(byAdding: .month, value: -1, to: state.displayedMonth) {
                    state.displayedMonth = prev
                }
                return .none

            case .nextMonthTapped:
                if let next = Calendar.current.date(byAdding: .month, value: 1, to: state.displayedMonth) {
                    state.displayedMonth = next
                }
                return .none
            }
        }
    }
}

